Deno.test("gates: addGate rejects empty name or command at the boundary", async () => {
  const dir = await makeTempDir();
  try {
    await buildLineage(dir);

    // Empty name
    let threw = false;
    try {
      await addGate(dir, "001", { name: "", command: "echo ok" });
    } catch (err) {
      threw = true;
      assertStringIncludes(String(err), "gate.name");
      assertStringIncludes(String(err), "non-empty");
    }
    assert(threw, "addGate must reject empty name");

    // Whitespace-only name
    threw = false;
    try {
      await addGate(dir, "001", { name: "   ", command: "echo ok" });
    } catch (err) {
      threw = true;
      assertStringIncludes(String(err), "gate.name");
    }
    assert(threw, "addGate must reject whitespace-only name");

    // Empty command
    threw = false;
    try {
      await addGate(dir, "001", { name: "tests", command: "" });
    } catch (err) {
      threw = true;
      assertStringIncludes(String(err), "gate.command");
      assertStringIncludes(String(err), "non-empty");
    }
    assert(threw, "addGate must reject empty command");

    // Manifest must not have been mutated by any of the rejected calls
    const direct = await listGates(dir, "001");
    assertEquals(direct.length, 0);
  } finally {
    await cleanup(dir);
  }
});

