export async function snapshot(
  dir: string,
  opts: { change?: string; summary?: string; addPaths?: string[] } = {},
): Promise<Variant> {
  // Validate addPaths at the boundary — passing an empty string or
  // non-string entry straight to `git add --` produces a cryptic
  // "fatal: empty string is not a valid pathspec" that looks like
  // corruption. Catch it here with an actionable message.
  if (opts.addPaths !== undefined) {
    if (!Array.isArray(opts.addPaths)) {
      throw new Error(
        `snapshot: opts.addPaths must be an array of strings (got ${typeof opts.addPaths})`,
      );
    }
    for (const p of opts.addPaths) {
      if (typeof p !== "string" || p.trim() === "") {
        throw new Error(
          `snapshot: opts.addPaths entries must be non-empty strings (got ${JSON.stringify(p)})`,
        );
