Deno.test("snapshot: addPaths validation rejects empty/non-string entries with actionable error", async () => {
  const dir = await makeTempDir();
  try {
    await init(dir);

    // Empty string entry → caller should be told entries must be non-empty strings.
    let msg = "";
    try {
      await snapshot(dir, { change: "x", addPaths: [""] });
    } catch (err) { msg = String(err); }
    assertStringIncludes(msg, "addPaths");
    assertStringIncludes(msg, "non-empty");

    // Whitespace-only entry → same boundary error.
    msg = "";
    try {
      await snapshot(dir, { change: "x", addPaths: ["  "] });
    } catch (err) { msg = String(err); }
    assertStringIncludes(msg, "addPaths");
    assertStringIncludes(msg, "non-empty");

    // Non-array → explicit type error rather than a cryptic iteration failure.
    msg = "";
    try {
      // deno-lint-ignore no-explicit-any
      await snapshot(dir, { change: "x", addPaths: "file.txt" as any });
    } catch (err) { msg = String(err); }
    assertStringIncludes(msg, "addPaths");
    assertStringIncludes(msg, "array");
  } finally {
    await cleanup(dir);
  }
});

